-- Anti-Double / Runtime Deduplication (Untuk memastikan efisiensi Memori)
for key, list in pairs(_G.DqymonDatabase) do
    local seen = {}
    local uniqueList = {}
    for _, word in ipairs(list) do
        local lowerWord = word:lower()
        if not seen[lowerWord] then
            seen[lowerWord] = true
            table.insert(uniqueList, lowerWord)
        end
    end
    _G.DqymonDatabase[key] = uniqueList
end

